  ('police-b20a8cf8-moex-00354', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '少年有少年事件處理法第3條第1項第2款所列情形之一，認有保障其健全自我成長之必要者， 移送該管少年法院，請問下列何者不屬於該款規定情形？', '["無理由離家", "無正當理由經常攜危險器械", "有施用毒品或迷幻物品之行為而尚未觸犯刑罰法律", "有預備犯罪或犯罪未遂而為法所不罰之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00355', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'essay', '英譯中：（10 分）
